import { extent } from 'd3-array';
import type { ScaleOrdinal, ScaleQuantize, ScaleThreshold } from 'd3-scale';
import { isUndefined } from 'lodash-es';
import { type PropsWithChildren } from 'react';

import { LayerColoringStrategyContext } from '../contexts/layer-coloring-strategy.context.js';
import { useColorScale } from '../hooks/use-color-scale.js';
import { useMapConfig } from '../hooks/use-map-config.js';
import { ColorParser } from '../types/coloring.js';
import type { MapLegendConfig } from '../types/legend.js';
import {
  isSequentialLegend,
  isThresholdLegend,
} from '../utils/build-scale-from-legend-config.js';

export function buildCategoricalScale(
  scale: ScaleOrdinal<string, string>,
): (value: string) => string | undefined {
  return (value: string) => {
    const categories = scale.domain();

    if (categories.includes(value)) {
      return scale(value);
    }
  };
}

export function buildNumericScale(
  scale: ScaleThreshold<number, string> | ScaleQuantize<string>,
): (value: number) => string | undefined {
  const scaleDomain = scale.domain();
  const [min, max] = extent(scaleDomain);

  if (isUndefined(min) || isUndefined(max)) {
    return (_: number) => undefined;
  }

  return (value: number) => {
    if (value && value >= min && value <= max) {
      return scale(value);
    }
  };
}

export function buildClampedScale(
  legend: MapLegendConfig,
  scale:
    | ScaleQuantize<string>
    | ScaleThreshold<number, string>
    | ScaleOrdinal<string, string>,
) {
  let colorParser;

  if (isSequentialLegend(legend)) {
    colorParser = buildNumericScale(scale as ScaleQuantize<string>);
  } else if (isThresholdLegend(legend)) {
    colorParser = buildNumericScale(scale as ScaleThreshold<number, string>);
  } else {
    colorParser = buildCategoricalScale(scale as ScaleOrdinal<string, string>);
  }

  return colorParser as ColorParser;
}

/**
 * This provider depends on {@link ColorScaleProvider} and will hold
 * a function to convert a value into a color or undefined in case is out
 * of the domain.
 * @example to get the color needed for the value of a data point based on the legend, the use of the function hold by this provider will be enough.
 *
 * @param children -
 */
export const LayerColorStrategyProvider = ({ children }: PropsWithChildren) => {
  const scale = useColorScale();

  const { legend } = useMapConfig();

  if (isUndefined(legend) || isUndefined(scale)) {
    return <>{children}</>;
  }

  const clampedScale = buildClampedScale(legend, scale);

  return (
    <LayerColoringStrategyContext.Provider value={clampedScale}>
      {children}
    </LayerColoringStrategyContext.Provider>
  );
};
